#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\Users\fallo\OneDrive\Desktop\репозитории\live-char-guide\node_modules\.pnpm\chromedriver@147.0.1\node_modules\chromedriver\node_modules;C:\Users\fallo\OneDrive\Desktop\репозитории\live-char-guide\node_modules\.pnpm\chromedriver@147.0.1\node_modules;C:\Users\fallo\OneDrive\Desktop\репозитории\live-char-guide\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/proc/cygdrive/c/Users/fallo/OneDrive/Desktop/репозитории/live-char-guide/node_modules/.pnpm/chromedriver@147.0.1/node_modules/chromedriver/node_modules:/proc/cygdrive/c/Users/fallo/OneDrive/Desktop/репозитории/live-char-guide/node_modules/.pnpm/chromedriver@147.0.1/node_modules:/proc/cygdrive/c/Users/fallo/OneDrive/Desktop/репозитории/live-char-guide/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../chromedriver/bin/chromedriver" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../chromedriver/bin/chromedriver" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../chromedriver/bin/chromedriver" $args
  } else {
    & "node$exe"  "$basedir/../chromedriver/bin/chromedriver" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
